# -*- coding: utf-8 -*-"""Verificación completa del entorno PyTorch ROCm/DirectML en WindowsCompatible con ROCm 6.4.4 (Preview) y builds CUDA/ROCm anteriores."""import torchimport platformimport subprocessprint("=" * 70)print("Verificación del entorno PyTorch + AMD ROCm/DirectML")print("=" * 70)print(f"Sistema operativo : {platform.system()} {platform.release()}")print(f"Versión de Python  : {platform.python_version()}")print(f"Versión de PyTorch : {torch.__version__}")print("-" * 70)# 1️⃣ Backend detectadocuda_ok = torch.cuda.is_available()xpu_ok = hasattr(torch, "xpu") and torch.xpu.is_available()hip_ver = getattr(torch.version, "hip", None)if cuda_ok:    print("✅ Backend activo: CUDA (implementación ROCm en Windows Preview)")    device = torch.device("cuda")    print("Nombre del dispositivo :", torch.cuda.get_device_name(0))elif xpu_ok:    print("✅ Backend activo: XPU (AMD ROCm/DirectML unificado)")    device = torch.device("xpu")    print("Nombre del dispositivo :", torch.xpu.get_device_name(0))else:    print("⚠️  No se detectó GPU compatible, usando CPU.")    device = torch.device("cpu")print("-" * 70)# 2️⃣ Prueba de operación tensorialtry:    x = torch.randn(1024, 1024, device=device)    y = torch.randn(1024, 1024, device=device)    z = torch.matmul(x, y)    print(f"Operación matricial completada en: {z.device}")except Exception as e:    print(f"❌ Error al ejecutar operación en {device}: {e}")print("-" * 70)# 3️⃣ Información detallada de entorno PyTorchtry:    print("📋 Resumen de entorno (torch.utils.collect_env):\n")    subprocess.run(["python", "-m", "torch.utils.collect_env"])except Exception:    print("No se pudo ejecutar torch.utils.collect_env")print("-" * 70)print(f"torch.cuda.is_available(): {cuda_ok}")print(f"torch.version.hip        : {hip_ver}")print("=" * 70)